import React, { useCallback, useMemo } from 'react';
import { TextField, FormControl, Select, MenuItem, InputLabel, Tooltip } from '@mui/material';
import { DatePicker, DateTimePicker } from '@mui/x-date-pickers';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs';
import dayjs from 'dayjs';
import utcPlugin from 'dayjs/plugin/utc.js';
import { useStateContext } from '../useRouter/StateProvider';
import utils from '../utils';
import { getDefaultOperator } from './helper';

dayjs.extend(utcPlugin);

const ToolbarFilter = ({
    column,
    filterModel,
    setFilterModel,
    lookupData,
    tTranslate,
    tOpts
}) => {
    const { systemDateTimeFormat, stateData } = useStateContext();
    const { fixedFilterFormat } = utils;

    // Find existing filter for this column
    const existingFilter = useMemo(() => {
        return filterModel?.items?.find(item => item.field === column.field);
    }, [filterModel, column.field]);

    const operator = existingFilter?.operator || column.toolbarFilter?.defaultOperator || getDefaultOperator(column.type);
    const isMultiple = operator === 'isAnyOf';

    // Get current filter value
    // If there's an existing filter, use its value (even if it's falsy like 0, false, "")
    const filterValue = useMemo(() => {
        if (['isEmpty', 'isNotEmpty'].includes(operator)) {
            return '';
        }

        if (!existingFilter) {
            return isMultiple ? [] : '';
        }
        
        // Ensure we always return a valid controlled value (never undefined)
        const value = existingFilter.value;
        if (value === undefined || value === null) {
            return isMultiple ? [] : '';
        }
        return value;
    }, [existingFilter, isMultiple]);
    // Handle filter change - use functional update to avoid filterModel dependency
    const handleFilterChange = useCallback((newValue) => {
        
        setFilterModel((prevFilterModel) => {
            const currentItems = prevFilterModel?.items || [];

            // If value is empty, remove filter
            if (newValue === '' || newValue === null || (Array.isArray(newValue) && newValue.length === 0)) {
                const newItems = currentItems.filter((item) => item.field !== column.field);
                return {
                    ...prevFilterModel,
                    items: newItems,
                };
            }

            // Update or add filter
            const newFilter = {
                field: column.field,
                operator: operator,
                value: newValue,
                type: column.type,
            };

            const otherFilters = currentItems.filter((item) => item.field !== column.field);
            return {
                ...prevFilterModel,
                items: [...otherFilters, newFilter],
            };
        });
    }, [column, setFilterModel]);

    // Get operator label/symbol for display
    const getOperatorLabel = useCallback((operator, type) => {
        // For number operators, use symbols
        if (type === 'number') {
            const symbolMap = {
                '=': '=',
                '!=': '≠',
                '>': '>',
                '>=': '≥',
                '<': '<',
                '<=': '≤'
            };
            return symbolMap[operator] || operator;
        }
        
        // For string operators, use verbose labels for non-obvious ones
        // Note: 'startsWith' is included for completeness but won't be displayed
        // due to shouldShowOperator logic below (it's the default and doesn't need a label)
        if (type === 'string') {
            const labelMap = {
                'contains': 'contains',
                'equals': 'exact match',
                'startsWith': 'starts with',
                'endsWith': 'ends with',
                'isEmpty': 'is empty',
                'isNotEmpty': 'is not empty'
            };
            return labelMap[operator] || operator;
        }
        
        // For other types, return the operator as-is or a readable version
        const labelMap = {
            'is': 'is',
            'not': 'is not',
            'isAnyOf': 'any of',
            'after': 'after',
            'onOrAfter': 'on or after',
            'before': 'before',
            'onOrBefore': 'on or before'
        };
        return labelMap[operator] || operator;
    }, []);

    // Render based on column type
    const renderFilterInput = () => {
        const baseLabel = column.toolbarFilter?.label || column.headerName || column.label || column.field;
        const operatorLabel = getOperatorLabel(operator, column.type);
        
        // For number fields, prepend operator symbol. For others, append operator text if verbose
        const shouldShowOperator = column.type === 'number' || (column.type === 'string' && operator !== 'startsWith');
        const label = shouldShowOperator 
            ? (column.type === 'number' ? `${operatorLabel} ${baseLabel}` : `${baseLabel} (${operatorLabel})`)
            : baseLabel;

        switch (column.type) {
            case 'string':
                return (
                    <TextField
                        variant="standard"
                        label={tTranslate(label, tOpts)}
                        value={filterValue}
                        onChange={(e) => handleFilterChange(e.target.value)}
                        type="text"
                        size="small"
                        sx={{ minWidth: 150 }}
                    />
                );

            case 'number':
                return (
                    <TextField
                        variant="standard"
                        label={tTranslate(label, tOpts)}
                        value={filterValue}
                        onChange={(e) => handleFilterChange(e.target.value)}
                        type="text"
                        inputProps={{ inputMode: 'numeric' }}
                        size="small"
                        sx={{ minWidth: 150 }}
                    />
                );

            case 'boolean': {
                const booleanSelectValue =
                    filterValue === '' || filterValue === undefined || filterValue === null
                        ? ''
                        : filterValue === true || filterValue === 'true'
                            ? 'true'
                            : filterValue === false || filterValue === 'false'
                                ? 'false'
                                : '';

                return (
                    <FormControl variant="standard" sx={{ minWidth: 150 }}>
                        <InputLabel>{tTranslate(label, tOpts)}</InputLabel>
                        <Select
                            value={booleanSelectValue}
                            onChange={(e) => {
                                const val = e.target.value;
                                let newValue;
                                if (val === '') {
                                    newValue = '';
                                } else if (val === 'true') {
                                    newValue = true;
                                } else if (val === 'false') {
                                    newValue = false;
                                } else {
                                    newValue = val;
                                }
                                handleFilterChange(newValue);
                            }}
                            size="small"
                        >
                            <MenuItem value="">{tTranslate('All', tOpts)}</MenuItem>
                            <MenuItem value="true">{tTranslate('True', tOpts)}</MenuItem>
                            <MenuItem value="false">{tTranslate('False', tOpts)}</MenuItem>
                        </Select>
                    </FormControl>
                );
            }

            case 'select':
            case 'singleSelect':
            case 'lookup':
                const options = column.customLookup || lookupData?.[column.lookup] || [];
                const normalizedOptions = typeof column.lookup === 'string'
                    ? options.map((option) => ({
                        label: option?.label || '',
                        value: option?.value ?? ''
                    }))
                    : options;

                const selectValue = utils.normalizeFilterValue({ value: filterValue, operator, isMultiple });
                const displayLimit = 1; // Show up to 1 selected options before collapsing into tooltip

                return (
                    <FormControl variant="standard" sx={{ minWidth: 150 }}>
                        <InputLabel>{tTranslate(label, tOpts)}</InputLabel>
                        <Select
                            value={selectValue}
                            onChange={(e) => handleFilterChange(e.target.value)}
                            multiple={isMultiple}
                            size="small"
                            renderValue={(selected) => {
                                // Normalize selected to array of values
                                const values = Array.isArray(selected) ? selected : (selected != null && selected !== '' ? [selected] : []);
                                const labels = values.map((v) => {
                                    // If the selected item is already an object with a label, use it
                                    if (v && typeof v === 'object' && 'label' in v) return tTranslate(v.label, tOpts);

                                    // Compare option values loosely (stringified) to handle type differences
                                    const opt = normalizedOptions.find((o) => String(o.value) === String(v));
                                    return opt ? tTranslate(opt.label, tOpts) : '';
                                }).filter(Boolean);

                                if (labels.length === 0) return '';
                                if (labels.length <= displayLimit) return labels.join(', ');

                                const firstTwo = labels.slice(0, displayLimit).join(', ');
                                const remaining = labels.length - displayLimit;
                                const full = labels.join(', ');

                                return (
                                    <Tooltip title={full} placement="top">
                                        <span>{`${firstTwo} +${remaining}`}</span>
                                    </Tooltip>
                                );
                            }}
                        >
                            {normalizedOptions.map((option) => (
                                <MenuItem key={option.value} value={option.value}>
                                    {tTranslate(option.label, tOpts)}
                                </MenuItem>
                            ))}
                        </Select>
                    </FormControl>
                );

            case 'date':
            case 'dateTime':
                const columnType = column.type;
                const filterFormat = fixedFilterFormat[columnType];
                const format = systemDateTimeFormat(columnType === 'date', false, stateData.dateTime);
                const DateComponent = columnType === 'dateTime' ? DateTimePicker : DatePicker;
                
                // Parse and validate date value once
                let dateValue = null;
                if (filterValue) {
                    const parsedDate = dayjs(filterValue);
                    dateValue = parsedDate.isValid() ? parsedDate : null;
                }

                return (
                    <LocalizationProvider dateAdapter={AdapterDayjs}>
                        <DateComponent
                            label={tTranslate(label, tOpts)}
                            format={format}
                            value={dateValue}
                            onChange={(newValue) => {
                                if (!newValue || !newValue.isValid()) {
                                    handleFilterChange(null);
                                } else {
                                    handleFilterChange(newValue.format(filterFormat));
                                }
                            }}
                            slotProps={{
                                textField: {
                                    variant: "standard",
                                    size: "small",
                                    sx: { minWidth: 150 }
                                }
                            }}
                        />
                    </LocalizationProvider>
                );

            default:
                return (
                    <TextField
                        variant="standard"
                        label={tTranslate(label, tOpts)}
                        value={filterValue}
                        onChange={(e) => handleFilterChange(e.target.value)}
                        size="small"
                        sx={{ minWidth: 150 }}
                    />
                );
        }
    };

    return renderFilterInput();
};

export default ToolbarFilter;
